mapper.select:
SELECT BOARD_ID AS postId, BOARD_TYPE AS boardType, STOCK_ID AS stockId, USER_ID AS userId, BOARD_TITLE AS title, VIEW_COUNT AS viewCnt, CAST(CREATE_DATE AS TIMESTAMP) AS createdAt FROM BOARD WHERE DELETE_DATE IS NULL
AND BOARD_TYPE = #{boardType}
AND STOCK_ID = #{stockId}
ORDER BY CREATE_DATE DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY
